const i = $input.first().json;
const sd = $getWorkflowStaticData("global");
sd.events = (sd.events || []).filter(e => Date.now() - e.ts < 3600000);
const max = parseInt($env.MAX_ACTIONS_PER_HOUR || "4", 10);
if (sd.events.length >= max) {
  return [{json: {allowed: false, detail: `rate limit: ${sd.events.length}/${max} write actions in the last hour - diagnosis-only mode`, recent: sd.events}}];
}
sd.events.push({ts: Date.now(), tool: i.tool || "?", target: i.target || "?"});
return [{json: {allowed: true, count: sd.events.length, max}}];
